char* findShortestCommonSupersequence(char* str1, char* str2) {
    int n = strlen(str1);
    int m = strlen(str2);

    // Step 1: DP Table
    // Dynamic allocation for large constraints (heap memory)
    int** dp = (int**)malloc((n + 1) * sizeof(int*));
    for (int i = 0; i <= n; i++)
        dp[i] = (int*)malloc((m + 1) * sizeof(int));

    for (int i = 0; i <= n; i++) {
        for (int j = 0; j <= m; j++) {
            if (i == 0 || j == 0)
                dp[i][j] = 0;
            else if (str1[i - 1] == str2[j - 1])
                dp[i][j] = 1 + dp[i - 1][j - 1];
            else
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1]);
        }
    }

    // Step 2: Backtrack
    // Max possible length is n + m
    char* res = (char*)malloc((n + m + 1) * sizeof(char));
    int index = 0;
    int i = n, j = m;

    while (i > 0 && j > 0) {
        if (str1[i - 1] == str2[j - 1]) {
            res[index++] = str1[i - 1];
            i--; j--;
        } else if (dp[i - 1][j] > dp[i][j - 1]) {
            res[index++] = str1[i - 1];
            i--;
        } else {
            res[index++] = str2[j - 1];
            j--;
        }
    }

    while (i > 0) { res[index++] = str1[i - 1]; i--; }
    while (j > 0) { res[index++] = str2[j - 1]; j--; }
    res[index] = '\0';

    // Cleanup DP table
    for(int k=0; k<=n; k++) free(dp[k]);
    free(dp);

    reverseString(res);
    return res;
}

